 1→import * as THREE from 'three';
 2→import { OrbitControls } from 'three/examples/jsm/controls/OrbitControls.js';
 3→import { DEFAULT_PRESET_NAME, PRESETS } from './previewConfig';
 4→import { fitCameraToBox } from './previewCameraMath';
 5→
 6→export function createInspectNavigation({ camera, domElement }) {
 7→  const controls = new OrbitControls(camera, domElement);
 8→  controls.enableDamping = true;
 9→  controls.dampingFactor = 0.08;
10→  controls.screenSpacePanning = true;
11→  controls.minDistance = 400;
12→  controls.maxDistance = 150000;
13→  controls.maxPolarAngle = Math.PI * 0.495;
14→
15→  const applyMouseBindings = (leftButtonRotateEnabled = true) => {
16→    controls.mouseButtons.LEFT = leftButtonRotateEnabled ? THREE.MOUSE.ROTATE : null;
17→    controls.mouseButtons.MIDDLE = THREE.MOUSE.DOLLY;
18→    controls.mouseButtons.RIGHT = THREE.MOUSE.PAN;
19→  };
20→
21→  applyMouseBindings(true);
22→
23→  let currentBounds = null;
24→  let currentPreset = DEFAULT_PRESET_NAME;
25→
26→  return {
27→    update() {
28→      controls.update();
29→    },
30→    setBounds(bounds) {
31→      currentBounds = bounds ? bounds.clone() : null;
32→    },
33→    setEnabled(enabled) {
34→      controls.enabled = enabled;
35→    },
36→    setLeftButtonRotateEnabled(enabled) {
37→      applyMouseBindings(enabled);
38→    },
39→    resetView() {
40→      if (!currentBounds) return;
41→      fitCameraToBox(camera, controls, currentBounds, currentPreset);
42→    },
43→    setProjectionPreset(presetName = DEFAULT_PRESET_NAME) {
44→      currentPreset = presetName in PRESETS ? presetName : DEFAULT_PRESET_NAME;
45→      if (!currentBounds) return;
46→      fitCameraToBox(camera, controls, currentBounds, currentPreset);
47→    },
48→    captureState() {
49→      return {
50→        position: camera.position.toArray(),
51→        target: controls.target.toArray(),
52→      };
53→    },
54→    restoreState(state) {
55→      if (!state?.position || !state?.target) return false;
56→      camera.position.fromArray(state.position);
57→      controls.target.fromArray(state.target);
58→      camera.updateProjectionMatrix();
59→      controls.update();
60→      return true;
61→    },
62→    dispose() {
63→      controls.dispose();
64→    },
65→  };
66→}
