  1→import * as THREE from 'three';
  2→import { PointerLockControls } from 'three/examples/jsm/controls/PointerLockControls.js';
  3→import { isTypingTarget } from '@/utils/keyboard';
  4→import { WALK_MOVE_SPEED, WALK_SPRINT_MULTIPLIER } from './previewConfig';
  5→
  6→const MOVEMENT_KEYS = new Set([
  7→  'KeyW',
  8→  'KeyA',
  9→  'KeyS',
 10→  'KeyD',
 11→  'KeyR',
 12→  'KeyF',
 13→  'ShiftLeft',
 14→  'ShiftRight',
 15→  'Escape',
 16→]);
 17→
 18→function isMovementKey(event) {
 19→  return MOVEMENT_KEYS.has(event.code);
 20→}
 21→
 22→export function createWalkNavigation({
 23→  camera,
 24→  domElement,
 25→  moveSpeed = WALK_MOVE_SPEED,
 26→  sprintMultiplier = WALK_SPRINT_MULTIPLIER,
 27→  onStateChange,
 28→  onExitRequested,
 29→}) {
 30→  const controls = new PointerLockControls(camera, domElement);
 31→  const movement = {
 32→    forward: false,
 33→    backward: false,
 34→    left: false,
 35→    right: false,
 36→    up: false,
 37→    down: false,
 38→    sprint: false,
 39→  };
 40→  const forwardVector = new THREE.Vector3();
 41→  const rightVector = new THREE.Vector3();
 42→  const movementVector = new THREE.Vector3();
 43→  const worldUp = new THREE.Vector3(0, 1, 0);
 44→
 45→  let enabled = false;
 46→
 47→  const emitStateChange = () => {
 48→    onStateChange?.({
 49→      enabled,
 50→      isLocked: controls.isLocked,
 51→    });
 52→  };
 53→
 54→  const clearMovement = () => {
 55→    movement.forward = false;
 56→    movement.backward = false;
 57→    movement.left = false;
 58→    movement.right = false;
 59→    movement.up = false;
 60→    movement.down = false;
 61→    movement.sprint = false;
 62→  };
 63→
 64→  const handleClick = () => {
 65→    if (!enabled || controls.isLocked) return;
 66→    controls.lock();
 67→  };
 68→
 69→  const handleKeyDown = (event) => {
 70→    if (!enabled) return;
 71→    if (isTypingTarget(event.target)) return;
 72→    if (!isMovementKey(event)) return;
 73→
 74→    event.preventDefault();
 75→    event.stopPropagation();
 76→    event.stopImmediatePropagation?.();
 77→
 78→    if (!controls.isLocked && event.code !== 'Escape') return;
 79→
 80→    switch (event.code) {
 81→      case 'KeyW':
 82→        movement.forward = true;
 83→        break;
 84→      case 'KeyS':
 85→        movement.backward = true;
 86→        break;
 87→      case 'KeyA':
 88→        movement.left = true;
 89→        break;
 90→      case 'KeyD':
 91→        movement.right = true;
 92→        break;
 93→      case 'KeyR':
 94→        movement.up = true;
 95→        break;
 96→      case 'KeyF':
 97→        movement.down = true;
 98→        break;
 99→      case 'ShiftLeft':
100→      case 'ShiftRight':
101→        movement.sprint = true;
102→        break;
103→      case 'Escape':
104→        clearMovement();
105→        onExitRequested?.();
106→        break;
107→      default:
108→        return;
109→    }
110→  };
111→
112→  const handleKeyUp = (event) => {
113→    if (!enabled || isTypingTarget(event.target)) return;
114→    if (!isMovementKey(event)) return;
115→
116→    event.preventDefault();
117→    event.stopPropagation();
118→    event.stopImmediatePropagation?.();
119→
120→    switch (event.code) {
121→      case 'KeyW':
122→        movement.forward = false;
123→        break;
124→      case 'KeyS':
125→        movement.backward = false;
126→        break;
127→      case 'KeyA':
128→        movement.left = false;
129→        break;
130→      case 'KeyD':
131→        movement.right = false;
132→        break;
133→      case 'KeyR':
134→        movement.up = false;
135→        break;
136→      case 'KeyF':
137→        movement.down = false;
138→        break;
139→      case 'ShiftLeft':
140→      case 'ShiftRight':
141→        movement.sprint = false;
142→        break;
143→      default:
144→        return;
145→    }
146→  };
147→
148→  controls.addEventListener('lock', emitStateChange);
149→  controls.addEventListener('unlock', emitStateChange);
150→  domElement.addEventListener('click', handleClick);
151→  window.addEventListener('keydown', handleKeyDown, true);
152→  window.addEventListener('keyup', handleKeyUp, true);
153→
154→  return {
155→    update(deltaSeconds) {
156→      if (!enabled || !controls.isLocked) return;
157→
158→      const distance = moveSpeed
159→        * (movement.sprint ? sprintMultiplier : 1)
160→        * deltaSeconds;
161→
162→      camera.updateMatrixWorld(true);
163→      camera.getWorldDirection(forwardVector).normalize();
164→      rightVector.setFromMatrixColumn(camera.matrixWorld, 0).normalize();
165→      movementVector.set(0, 0, 0);
166→
167→      if (movement.forward) movementVector.add(forwardVector);
168→      if (movement.backward) movementVector.sub(forwardVector);
169→      if (movement.left) movementVector.sub(rightVector);
170→      if (movement.right) movementVector.add(rightVector);
171→      if (movement.up) movementVector.add(worldUp);
172→      if (movement.down) movementVector.sub(worldUp);
173→
174→      if (!movementVector.lengthSq()) return;
175→
176→      movementVector.normalize().multiplyScalar(distance);
177→      camera.position.add(movementVector);
178→    },
179→    setEnabled(nextEnabled) {
180→      enabled = nextEnabled;
181→      clearMovement();
182→      if (!enabled && controls.isLocked) {
183→        controls.unlock();
184→      }
185→      emitStateChange();
186→    },
187→    isLocked() {
188→      return controls.isLocked;
189→    },
190→    capturePose() {
191→      return {
192→        position: camera.position.toArray(),
193→        quaternion: camera.quaternion.toArray(),
194→      };
195→    },
196→    restorePose(pose) {
197→      if (!pose?.position) return false;
198→
199→      camera.position.fromArray(pose.position);
200→      if (pose.quaternion) {
201→        camera.quaternion.fromArray(pose.quaternion);
202→      } else if (pose.lookAt) {
203→        const lookAt = Array.isArray(pose.lookAt)
204→          ? new THREE.Vector3().fromArray(pose.lookAt)
205→          : new THREE.Vector3(pose.lookAt.x, pose.lookAt.y, pose.lookAt.z);
206→        camera.lookAt(lookAt);
207→      }
208→      camera.updateMatrixWorld(true);
209→      return true;
210→    },
211→    dispose() {
212→      clearMovement();
213→      if (controls.isLocked) {
214→        controls.unlock();
215→      }
216→      controls.dispose?.();
217→      controls.disconnect?.();
218→      controls.removeEventListener('lock', emitStateChange);
219→      controls.removeEventListener('unlock', emitStateChange);
220→      domElement.removeEventListener('click', handleClick);
221→      window.removeEventListener('keydown', handleKeyDown, true);
222→      window.removeEventListener('keyup', handleKeyUp, true);
223→    },
224→  };
225→}
