177→function SketchInner() {
178→  const { project, isDirty, dispatch } = useSketch();
179→  const { workspaceMode, activeSheetId, dispatch: editorDispatch } = useSketchEditor();
180→  const [showLoadModal, setShowLoadModal] = useState(false);
181→  const [showTemplateDialog, setShowTemplateDialog] = useState(false);
182→  const [fileHandle, setFileHandle] = useState(null);
183→
184→  // Autosave
185→  useSketchAutosave(project, isDirty, dispatch);
186→
187→  // beforeunload warning
188→  useEffect(() => {
189→    const handler = (e) => {
190→      if (isDirty) {
191→        e.preventDefault();
192→        e.returnValue = '';
193→      }
194→    };
195→    window.addEventListener('beforeunload', handler);
196→    return () => window.removeEventListener('beforeunload', handler);
197→  }, [isDirty]);
198→
199→  // Ctrl+S file save
200→  useEffect(() => {
201→    const handler = async (e) => {
202→      if ((e.ctrlKey || e.metaKey) && e.key === 's') {
203→        e.preventDefault();
204→        try {
205→          const result = await exportSketchProjectFile(project, { fileHandle });
206→          if (result.fileHandle) setFileHandle(result.fileHandle);
207→          await saveSketchProject(project);
208→          dispatch({ type: 'MARK_SAVED' });
209→        } catch (err) {
210→          if (!isFilePickerAbortError(err)) {
211→            console.error('Save failed:', err);
212→          }
213→        }
214→      }
215→    };
216→    window.addEventListener('keydown', handler);
217→    return () => window.removeEventListener('keydown', handler);
218→  }, [project, fileHandle, dispatch]);
219→
220→  // If active sheet was deleted, revert to model mode
221→  useEffect(() => {
222→    if (workspaceMode === 'sheet' && activeSheetId) {
223→      const sheetExists = (project.sheets || []).some((s) => s.id === activeSheetId);
224→      if (!sheetExists) {
225→        editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'model' });
226→        editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: null });
227→      }
228→    }
229→  }, [workspaceMode, activeSheetId, project.sheets, editorDispatch]);
230→
231→  const handleNew = useCallback(() => {
232→    if (isDirty && !window.confirm('You have unsaved changes. Start a new project?')) return;
233→    dispatch({ type: 'SKETCH_NEW' });
234→    setFileHandle(null);
235→  }, [isDirty, dispatch]);
236→
237→  const handleSave = useCallback(async () => {
238→    try {
239→      const result = await exportSketchProjectFile(project, { fileHandle });
240→      if (result.fileHandle) setFileHandle(result.fileHandle);
241→      await saveSketchProject(project);
242→      dispatch({ type: 'MARK_SAVED' });
243→    } catch (err) {
244→      if (!isFilePickerAbortError(err)) {
245→        console.error('Save failed:', err);
246→      }
247→    }
248→  }, [project, fileHandle, dispatch]);
249→
250→  const handleLoadClick = useCallback(() => {
251→    setShowLoadModal(true);
252→  }, []);
253→
254→  const isSheetMode = workspaceMode === 'sheet';
255→
256→  return (
257→    <SketchProjectContext.Provider value={{ handleNew, handleSave, handleLoadClick, fileHandle, setFileHandle, showTemplateDialog, setShowTemplateDialog }}>
258→      <div className={styles.layout}>
259→        <div className={styles.toolbar}>
260→          <SketchToolbar />
261→        </div>
262→        <div className={styles.sidebar}>
263→          <SketchSidebar />
264→        </div>
265→        <div className={styles.canvas}>
266→          {isSheetMode ? (
267→            <Suspense fallback={<div className={styles.previewFallback}>Loading sheet...</div>}>
268→              <SketchSheetCanvas />
269→            </Suspense>
270→          ) : (
271→            <SketchViewport />
272→          )}
273→        </div>
274→        <div className={styles.rightPanel}>
275→          <SketchPropertiesPanel />
276→        </div>
277→      </div>
278→      {showLoadModal && <SketchLoadModal onClose={() => setShowLoadModal(false)} />}
279→      {showTemplateDialog && (
280→        <TemplateDialog
281→          onClose={() => setShowTemplateDialog(false)}
282→          onGenerate={(templateType, params) => {
283→            if (templateType === '__free_canvas__') {
284→              const object = createSketchObject((params.objectName || 'Custom Object').trim() || 'Custom Object', {
285→                id: generateId('obj'),
286→                category: params.category || 'general',
287→                summary: 'Free-canvas custom object',
288→                editingPolicy: 'manual',
289→                source: 'custom',
290→              });
291→              const assembly = createAssembly((params.moduleName || 'Module 1').trim() || 'Module 1', {
292→                objectId: object.id,
293→                category: params.category || 'general',
294→                description: 'Primary editable module',
295→                source: 'manual',
296→              });
297→              dispatch({ type: 'OBJECT_CREATE', object, assemblies: [assembly] });
298→              editorDispatch({ type: 'DISMISS_EMPTY_STATE' });
299→              editorDispatch({ type: 'SET_TOOL', tool: SKETCH_TOOLS.SOLID });
300→              editorDispatch({ type: 'ENTER_ASSEMBLY_EDIT', assemblyId: assembly.id });
301→              return;
302→            }
303→
304→            const objectId = generateId('obj');
305→            dispatch({ type: 'TEMPLATE_GENERATE', templateType, params, objectId });
306→            editorDispatch({ type: 'DISMISS_EMPTY_STATE' });
307→            editorDispatch({ type: 'SET_ACTIVE_ASSEMBLY', assemblyId: null });
308→            editorDispatch({ type: 'SELECT_OBJECT', id: objectId, objectType: 'object' });
309→          }}
310→        />
311→      )}
312→    </SketchProjectContext.Provider>
313→  );
314→}
