 25→function createBoundsFromPoints(points, baseElevation, topElevation) {
 26→  if (!points?.length) {
 27→    return {
 28→      minX: 0,
 29→      maxX: 0,
 30→      minY: 0,
 31→      maxY: 0,
 32→      minElevation: baseElevation,
 33→      maxElevation: topElevation,
 34→    };
 35→  }
 36→
 37→  return {
 38→    minX: Math.min(...points.map((point) => point.x)),
 39→    maxX: Math.max(...points.map((point) => point.x)),
 40→    minY: Math.min(...points.map((point) => point.y)),
 41→    maxY: Math.max(...points.map((point) => point.y)),
 42→    minElevation: baseElevation,
 43→    maxElevation: topElevation,
 44→  };
 45→}
