 62→function createLinearBoxDescriptor(id, kind, startPoint, endPoint, width, baseElevation, height, metadata = {}) {
 63→  const outline = wallOutline({
 64→    start: { x: startPoint.x, y: startPoint.y },
 65→    end: { x: endPoint.x, y: endPoint.y },
 66→    thickness: width,
 67→  });
 68→  const direction = wallDirection({
 69→    start: { x: startPoint.x, y: startPoint.y },
 70→    end: { x: endPoint.x, y: endPoint.y },
 71→  });
 72→  const topElevation = baseElevation + height;
 73→
 74→  return {
 75→    id,
 76→    kind,
 77→    geometry: 'box',
 78→    center: {
 79→      x: (startPoint.x + endPoint.x) / 2,
 80→      y: (startPoint.y + endPoint.y) / 2,
 81→    },
 82→    size: {
 83→      x: wallLength({ start: startPoint, end: endPoint }),
 84→      y: height,
 85→      z: width,
 86→    },
 87→    rotation: Math.atan2(direction.y, direction.x),
 88→    baseElevation,
 89→    materialKey: metadata.materialKey || kind,
 90→    metadata,
 91→    bounds: createBoundsFromPoints(outline, baseElevation, topElevation),
 92→  };
 93→}
