 54→function createPanelMesh(part, isSelected) {
 55→  const color = isSelected ? SELECTED_TINT : WOOD_COLOR;
 56→  const mesh = createBoxMesh(part.width, part.thickness, part.depth, color);
 57→  // Three.js: x = part.x + w/2, y = part.z + h/2, z = part.y + d/2
 58→  mesh.position.set(
 59→    part.position.x + part.width / 2,
 60→    part.position.z + part.thickness / 2,
 61→    part.position.y + part.depth / 2
 62→  );
 63→  addEdges(mesh);
 64→  return mesh;
 65→}
