 91→function createFrameMesh(part, isSelected) {
 92→  const color = isSelected ? SELECTED_TINT : 0xA0522D;
 93→  let w, h, d;
 94→
 95→  if (part.axis === 'y') {
 96→    w = part.width;
 97→    h = part.height;
 98→    d = part.length;
 99→  } else {
100→    w = part.length;
101→    h = part.height;
102→    d = part.width;
103→  }
104→
105→  const mesh = createBoxMesh(w, h, d, color);
106→  mesh.position.set(
107→    part.position.x + w / 2,
108→    part.position.z + h / 2,
109→    part.position.y + d / 2
110→  );
111→  addEdges(mesh);
112→  return mesh;
113→}
114→
115→function createSolidMesh(part, isSelected) {
116→  const color = isSelected ? SELECTED_TINT : 0xC6A46A;
117→  const shape = new THREE.Shape();
118→  const points = part.profilePoints || [];
119→  if (points.length < 3) return null;
120→
121→  shape.moveTo(points[0].u, points[0].v);
122→  for (let index = 1; index < points.length; index += 1) {
123→    shape.lineTo(points[index].u, points[index].v);
124→  }
125→  shape.closePath();
126→
127→  const geometry = new THREE.ExtrudeGeometry(shape, {
128→    depth: Math.max(1, part.extrusionDepth || 120),
129→    bevelEnabled: false,
130→    steps: 1,
131→  });
132→  const material = new THREE.MeshStandardMaterial({
133→    color,
134→    roughness: 0.7,
135→    metalness: 0.05,
136→    side: THREE.DoubleSide,
137→  });
138→  const mesh = new THREE.Mesh(geometry, material);
139→
140→  const plane = getSolidPlane(part);
141→  const origin = domainPointToThree(plane.origin);
142→  const uAxis = domainVectorToThree(plane.uAxis);
143→  const vAxis = domainVectorToThree(plane.vAxis);
144→  const normal = domainVectorToThree(plane.normal);
145→  const basis = new THREE.Matrix4().makeBasis(uAxis, vAxis, normal);
146→  basis.setPosition(origin);
147→  mesh.applyMatrix4(basis);
148→  addEdges(mesh);
149→  return mesh;
150→}
