152→function isPartSelected(part, selection) {
153→  if (!selection) return false;
154→  if (selection.selectedType === 'object') return part.objectId === selection.selectedId;
155→  if (selection.selectedType === 'assembly') return part.assemblyId === selection.selectedId;
156→  return part.id === selection.selectedId;
157→}
