159→export function buildSketchPreviewRoot(parts, selection) {
160→  const root = new THREE.Group();
161→
162→  for (const part of parts) {
163→    // Skip dimension, cutout, hole in 3D for V1
164→    if (part.type === 'dimension' || part.type === 'cutout' || part.type === 'hole') continue;
165→
166→    const isSelected = isPartSelected(part, selection);
167→    let mesh;
168→
169→    switch (part.type) {
170→      case 'panel':
171→        mesh = createPanelMesh(part, isSelected);
172→        break;
173→      case 'leg':
174→        mesh = createLegMesh(part, isSelected);
175→        break;
176→      case 'frame':
177→        mesh = createFrameMesh(part, isSelected);
178→        break;
179→      case 'solid':
180→        mesh = createSolidMesh(part, isSelected);
181→        break;
182→      default:
183→        continue;
184→    }
185→
186→    if (mesh) {
187→      mesh.userData.previewTarget = { sourceId: part.id, kind: 'part' };
188→      root.add(mesh);
189→    }
190→  }
191→
192→  return root;
193→}
