153→function titleForObject(selectedType, object, floor) {
154→  switch (selectedType) {
155→    case 'beam':
156→      return getBeamDisplayLabel(object, floor.columns || []);
157→    case 'column':
158→      return getColumnListLabel(object, floor.columns || []);
159→    case 'slab':
160→      return getSlabDisplayLabel(object);
161→    case 'stair':
162→      return getStairDisplayLabel(object);
163→    case 'landing':
164→      return getLandingDisplayLabel(object);
165→    case 'wall':
166→    case 'door':
167→    case 'window':
168→      return `${TYPE_LABELS[selectedType]} ${object.id.split('_').pop()}`;
169→    case 'fixture':
170→      return FIXTURE_TYPE_LABELS[object.fixtureType] || 'Fixture';
171→    case 'railing': {
172→      const typeLabel = object.type ? object.type.charAt(0).toUpperCase() + object.type.slice(1) : 'Railing';
173→      return `${typeLabel} Railing ${object.id.split('_').pop()}`;
174→    }
175→    case 'roofSystem':
176→      return object.name || 'Roof';
177→    case 'parapet':
178→      return object.name || `Parapet ${object.id.split('_').pop()}`;
179→    case 'drain':
180→      return object.name || `Drain ${object.id.split('_').pop()}`;
181→    case 'roofOpening':
182→      return object.name || `Roof Opening ${object.id.split('_').pop()}`;
183→    case 'trussSystem':
184→      return object.name || 'Truss System';
185→    case 'trussInstance': {
186→      const trussType = resolveTrussType(object.trussTypeId);
187→      return `${trussType.name} ${object.id.split('_').pop()}`;
188→    }
189→    default:
190→      return object?.id || TYPE_LABELS[selectedType] || 'Object';
191→  }
192→}
