194→function rowsForObject(selectedType, object, floor, roofSystem = null) {
195→  switch (selectedType) {
196→    case 'wall':
197→      return [
198→        mmRow('Length', wallLength(object)),
199→        mmRow('Thickness', object.thickness),
200→        mmRow('Height', object.height),
201→      ];
202→    case 'beam':
203→      return [
204→        mmRow('Span', beamLength(object, floor.columns || [])),
205→        mmRow('Width', object.width),
206→        mmRow('Depth', object.depth),
207→      ];
208→    case 'column':
209→      return [
210→        mmRow('Width', object.width),
211→        mmRow('Depth', object.depth),
212→        mmRow('Height', object.height),
213→      ];
214→    case 'slab':
215→      return [
216→        mmRow('Thickness', object.thickness),
217→        mmRow('Elevation', object.elevation),
218→        areaRow('Area', slabArea(object)),
219→      ];
220→    case 'stair':
221→      return [
222→        mmRow('Width', object.width),
223→        mmRow('Run', stairRun(object)),
224→        mmRow('Total Rise', stairTotalRise(object)),
225→        { label: 'Roof Access', value: object.roofAccess?.roofOpeningId
226→          ? (findRoofOpeningById(roofSystem, object.roofAccess.roofOpeningId)?.name || 'Linked roof opening')
227→          : 'None' },
228→      ];
229→    case 'landing':
230→      return [
231→        mmRow('Width', object.width),
232→        mmRow('Depth', object.depth),
233→        mmRow('Thickness', object.thickness),
234→      ];
235→    case 'door':
236→      return [
237→        mmRow('Width', object.width),
238→        mmRow('Height', object.height),
239→        mmRow('Sill', object.sillHeight),
240→      ];
241→    case 'window':
242→      return [
243→        mmRow('Width', object.width),
244→        mmRow('Height', object.height),
245→        mmRow('Sill', object.sillHeight),
246→      ];
247→    case 'fixture':
248→      return [
249→        mmRow('Width', object.width),
250→        mmRow('Depth', object.depth),
251→      ];
252→    case 'railing':
253→      return [
254→        mmRow('Length', railingLength(object)),
255→        mmRow('Height', object.height),
256→        mmRow('Width', object.width),
257→        { label: 'Type', value: object.type ? object.type.charAt(0).toUpperCase() + object.type.slice(1) : '—' },
258→      ];
259→    case 'roofSystem':
260→      return [
261→        { label: 'Type', value: getRoofTypeLabel(object.roofType || 'flat') },
262→        mmRow('Base Elev.', object.baseElevation),
263→        mmRow('Slab Thick.', object.slabThickness),
264→        ...(object.roofType === 'flat'
265→          ? [{ label: 'Finish Slope', value: `${Number(object.finishSlope || 0).toFixed(1)}%` }]
266→          : object.roofType === 'custom'
267→            ? [
268→                { label: 'Roof Planes', value: String((object.roofPlanes || []).length) },
269→                { label: 'Ridges', value: String((object.ridges || []).length) },
270→                { label: 'Valleys', value: String((object.valleys || []).length) },
271→                { label: 'Hips', value: String((object.hips || []).length) },
272→              ]
273→          : [
274→              ...(object.trussAttachmentId ? [{
275→                label: 'Pitch Source',
276→                value: object.pitchSource === 'manual' ? 'Manual Slope' : 'Follow Truss',
277→              }] : []),
278→              { label: 'Roof Slope', value: `${Number(object.pitch?.slope || 0).toFixed(1)}%` },
279→              { label: 'Slope Dir.', value: `${Math.round(roofPitchDirectionToAngle(object.pitch?.direction))}°` },
280→              mmRow('Overhang', object.pitch?.overhang),
281→              ...(object.roofType === 'gable' ? [mmRow('Ridge Offset', object.pitch?.ridgeOffset)] : []),
282→            ]),
283→      ];
284→    case 'parapet': {
285→      const resolvedParapet = resolveParapetLine(object, roofSystem) || object;
286→      return [
287→        mmRow('Length', wallLength({ start: resolvedParapet.startPoint, end: resolvedParapet.endPoint })),
288→        mmRow('Height', object.height),
289→        mmRow('Thickness', object.thickness),
290→        { label: 'Mode', value: object.attachment?.type === 'roof_edge' ? 'Roof Edge' : 'Free' },
291→      ];
292→    }
293→    case 'drain':
294→      return [
295→        mmRow('Diameter', object.diameter),
296→        mmRow('Invert Offset', object.invertOffset),
297→      ];
298→    case 'roofOpening':
299→      return [
300→        { label: 'Type', value: normalizeRoofOpeningType(object.type || 'opening').toUpperCase() },
301→        areaRow('Area', Math.abs((object.boundaryPoints || []).reduce((sum, point, index, points) => {
302→          const next = points[(index + 1) % points.length];
303→          return sum + (point.x * next.y - next.x * point.y);
304→        }, 0) / 2)),
305→        mmRow('Curb Height', object.curbHeight),
306→      ];
307→    case 'trussSystem':
308→      {
309→        const purlinTotalLength = getTrussSystemPurlinTotalLength(object);
310→        return [
311→          { label: 'Floor', value: floor?.name || 'Unassigned' },
312→          mmRow('Base Elev.', object.baseElevation),
313→          { label: 'Rotation', value: `${Number(object.planRotationOffsetDegrees || 0).toFixed(1)}°` },
314→          { label: 'Instances', value: String((object.trussInstances || []).length) },
315→          { label: 'Purlins', value: object.purlinSystem?.enabled ? 'Enabled' : 'Disabled' },
316→          ...(object.purlinSystem?.enabled
317→            ? [
318→                mmRow('Purlin Spacing', object.purlinSystem.spacing),
319→                mmRow('Purlin Start', object.purlinSystem.startOffset),
320→                mmRow('Purlin End', object.purlinSystem.endOffset),
321→                mmRow('Purlin OH A', object.purlinSystem.overhangStart),
322→                mmRow('Purlin OH B', object.purlinSystem.overhangEnd),
323→                {
324→                  label: 'Purlin Total Length',
325→                  value: purlinTotalLength > 0 ? formatMeasurement(purlinTotalLength) : 'Single support only',
326→                },
327→                { label: 'Purlin Section', value: `${formatMeasurement(object.purlinSystem.width)} x ${formatMeasurement(object.purlinSystem.depth)}` },
328→                { label: 'Purlin Material', value: materialLabel(object.purlinSystem.material) },
329→              ]
330→            : []),
331→          { label: 'Roof Link', value: roofSystem?.trussAttachmentId === object.id ? (roofSystem.name || 'Active Roof Source') : 'Not Roof Source' },
332→        ];
333→      }
334→    case 'trussInstance': {
335→      const trussType = resolveTrussType(object.trussTypeId);
336→      return [
337→        { label: 'Type', value: trussType.name },
338→        { label: 'Family', value: trussShapeLabel(trussType.family) },
339→        { label: 'Shape', value: trussShapeLabel(trussType.shape || trussType.family) },
340→        { label: 'Roof Fit', value: trussType.attachedRoofType ? trussType.attachedRoofType.toUpperCase() : 'UNSUPPORTED' },
341→        { label: 'Material', value: materialLabel(object.material || trussType.material) },
342→        { label: 'Web Pattern', value: trussType.webPattern?.label || trussType.webPattern?.key || '—' },
343→        { label: 'Support A', value: trussSupportLabel(floor, object.supportBeamIds?.start) },
344→        { label: 'Support B', value: trussSupportLabel(floor, object.supportBeamIds?.end) },
345→        mmRow('Span', object.span),
346→        mmRow('Rise', object.rise),
347→        { label: 'Pitch', value: `${Number(object.pitch || 0).toFixed(1)}%` },
348→        mmRow('Spacing', object.spacing),
349→        { label: 'Count', value: String(object.count || 1) },
350→        mmRow('Bearing A', object.bearingOffsets?.start),
351→        mmRow('Bearing B', object.bearingOffsets?.end),
352→        mmRow('Overhang A', object.overhangs?.start),
353→        mmRow('Overhang B', object.overhangs?.end),
354→        { label: 'Roof Link', value: object.roofAttachmentId || 'None' },
355→      ];
356→    }
357→    default:
358→      return [];
359→  }
360→}
